def capacity_rule(model, j, h):
    return model.y[j, h] <= sum(model.x[i, j] * model.p[i, j] for i in model.i)

model.capacity = Constraint(model.j, model.h, rule=capacity_rule)

def fleet_availability_rule(model, i):
    return sum(model.x[i, j] for j in model.j) <= model.aircraft[i]

model.fleet_availability = Constraint(model.i, rule=fleet_availability_rule)

def demand_satisfaction_rule(model, j):
    return sum(model.pcap[i, j] * model.x[i, j] for i in model.i) + model.bumped[j] >= model.fixeddemand[j]

model.demand_satisfaction = Constraint(model.j, rule=demand_satisfaction_rule)

def demand_coverage_rule(model, j):
    return sum(model.x[i, j] * model.pcap[i, j] for i in model.i) + model.bumped[j] >= model.fixeddemand[j]

model.demand_coverage = Constraint(model.j, rule=demand_coverage_rule)

def bumped_balance_rule(model, j, h):
    return model.b[j, h] == model.dd[j, h] - model.y[j, h]

model.bumped_balance = Constraint(model.j, model.h, rule=bumped_balance_rule)

def supply_rule(model, i):
    return sum(model.x[i, j] for j in model.j) + model.sslack[i] == model.a[i]

model.supply = Constraint(model.i, rule=supply_rule)

def demand_rule(model, j):
    return sum(model.x[i, j] for i in model.i) - model.dslack[j] == model.b[j]

model.demand = Constraint(model.j, rule=demand_rule)

def cost_rule(model):
    return model.z == sum(model.c[i, j] * model.x[i, j] for i in model.i for j in model.j)

model.cost = Constraint(rule=cost_rule)

def demand_capacity_rule(model, j, h):
    return model.dd[j, h] - model.bh[j, h] <= model.z[j]

model.demand_capacity = Constraint(model.j, model.h, rule=demand_capacity_rule)

def plant_supply_balance_rule(model, i):
    return sum(model.x[i, j] for j in model.j) + model.sslack[i] == model.a[i]

model.plant_supply_balance = Constraint(model.i, rule=plant_supply_balance_rule)

def demand_balance_rule(model, g):
    return sum(model.outp[g, m] for m in model.m) == model.dempr_demand[g]

model.demand_balance = Constraint(model.g, rule=demand_balance_rule)

def machine_availability_rule(model, m):
    return sum(model.outp[g, m] / model.prate[g, m] for g in model.g) <= model.avail[m]

model.machine_availability = Constraint(model.m, rule=machine_availability_rule)

def production_capacity_rule(model, t):
    return sum(model.x[p, t] for p in model.p) <= model.m

model.production_capacity = Constraint(model.t, rule=production_capacity_rule)

def lane_limit_rule(model, i, j):
    return model.x[i, j] <= model.min_ab[i, j] * model.xind[i, j]

model.lane_limit = Constraint(model.i, model.j, rule=lane_limit_rule)

def max_production_output_rule(model, t):
    return sum(model.x[p, t] for p in model.p) <= model.m

model.max_production_output = Constraint(model.t, rule=max_production_output_rule)

model.local_purchase_limit = Constraint(model.cposm, model.t, rule=def_local_purchase_limit_rule)

def def_local_purchase_limit_rule(model, c, i, t):
    return model.u[c, i, t] <= model.pdlim[i, c]

model.h_cap = Constraint(model.m, model.i, model.te, rule=h_cap_rule)

def h_cap_rule(model, m, i, te):
    if (m, i) not in model.hpos:
        return Constraint.Skip
    return model.h[m, i, te] == sum(model.hp[n, i, m] * model.yp[n, te] for n in model.n if (n, i, m) in model.hpos)

def npk_utilization_rule(model, i, t):
    total_npk_usage = 0
    for g, m, i in model.mpos:
        if i == i:
            total_npk_usage += sum(model.z[g, p, i, t] * model.b[m, p] for p in model.p if (g, m, i) in model.mpos)
    return total_npk_usage >= model.umin[t] * sum(model.k[m, i, t] for m in model.m if (g, m, i) in model.mpos)

model.npk_util = Constraint(model.i, model.t, rule=npk_utilization_rule)

def phit_rule(model, w, t):
    return model.phit[w, t] == model.tariffvi * model.tvi[w, t] + model.tariffvf * model.tvf[w, t]

model.phit = Constraint(model.w, model.t, rule=phit_rule)

def capacity_rule(model, g, m, i, t):
    if (g, m, i) not in model.mpos:
        return Constraint.Skip

    capacity_used = sum(model.b[m,p] * model.z[g,p,i,t] for p in model.p)

    if g == 'old':
        capacity_available = model.k[m,i,t]
    else:
        capacity_available = model.unew * sum(model.h[m,i,te] * model.ts[t,te] for te in model.te)

    return capacity_used <= capacity_available

model.capacity_limit = Constraint(model.mpos * model.t, rule=capacity_rule)

model.phi = Constraint(model.w, model.t, rule=phi_rule)

def phi_rule(model, w, t):
    return model.phi[w,t] == (model.phik[w,t] + model.phip[w,t] + model.phig[w,t] + model.phiw[w,t] + model.phim[w,t] + model.phit[w,t] + model.phil[w,t] - model.phie[w,t])

def phiw_working_capital_rule(model, w, t):
    return model.phiw[w, t] - 0.05 * (model.phip[w, t] + model.phig[w, t] + model.tvi[w, t])

model.phiw_working_capital = Constraint(model.w, model.t, rule=phiw_working_capital_rule)

model.process_capacity = Constraint(model.w, model.i, model.mpos, model.g, model.p, model.t, rule=process_capacity_rule)

def process_capacity_rule(model, w, i, m, g, p, t):
    if (m, i, g) not in model.mpos:
        return Constraint.Skip
    existing_capacity = model.k[m, i, t] if g == 'old' else 0
    expanded_capacity = sum(model.h[m, i, te] for te in model.te if ts[t, te] == 1)
    max_capacity = existing_capacity + expanded_capacity
    return model.z[g, p, i, t] <= max_capacity

model.final_product_shipment = Constraint(model.mc, model.t, rule=final_product_shipment_rule)

def final_product_shipment_rule(model, cf, i, j, t):
    return model.xf[cf, i, j, t] >= 0

model.regional_nutrient_demand = Constraint(model.wj, model.cq, model.t, rule=regional_nutrient_demand_rule)

def regional_nutrient_demand_rule(model, w, j, cq, t):
    total_nutrient = sum(model.xf[cf, i, j, t] * alpha[cf, cq] for i in model.i if (i, j) in model.wj and cf in model.cf)
    return total_nutrient >= model.d[j, cq, t]

model.regional_min_ammonium_sulfate = Constraint(model.wj, model.t, rule=regional_min_ammonium_sulfate_rule)

def regional_min_ammonium_sulfate_rule(model, w, j, t):
    return model.xf['amm-sulf', i, j, t] >= model.db[j, t] for i in model.i if (i, j) in model.wj

model.package_selection_binary = Constraint(model.wn, model.te, rule=package_selection_binary_rule)

def package_selection_binary_rule(model, w, n, te):
    return model.yp[n, te] in [0, 1]

model.country_package_minimum = Constraint(model.w, rule=country_package_minimum_rule)

def country_package_minimum_rule(model, w):
    total_packages = sum(model.yp[n, te] for n in model.n if (w, n) in model.wn and te in model.te)
    return total_packages >= model.npack

model.package_expansion_limit = Constraint(model.w, rule=package_expansion_limit_rule)

def package_expansion_limit_rule(model, w):
    periods_with_packages = sum(model.yp[n, te] for n in model.n if (w, n) in model.wn and te in model.te)
    return periods_with_packages <= model.nnum

model.package_country_difference = Constraint(model.w, rule=package_country_difference_rule)

def package_country_difference_rule(model, w1):
    for w2 in model.w:
        if w1 != w2:
            diff = abs(sum(model.yp[n, te] for n in model.n if (w1, n) in model.wn and te in model.te) - 
                       sum(model.yp[n, te] for n in model.n if (w2, n) in model.wn and te in model.te))
            return diff <= model.dpack
